# SDD-TEE (SDD Token Efficiency Evaluation) Configuration v2
# CodeSpec 7-Stage × OpenSpec OPSX

project:
  name: agentcube
  repo_url: https://github.com/ShijunDeng/agentcube.git
  deepwiki_url: https://deepwiki.com/ShijunDeng/agentcube

methodology:
  framework: CodeSpec 7-Stage Workflow
  toolchain: OpenSpec OPSX
  ar_granularity: capability/feature level
  stages:
    - {id: ST-0, name: AR 输入, opsx: "/opsx:new", artifact: "变更目录"}
    - {id: ST-1, name: 需求澄清, opsx: "/opsx:ff → proposal", artifact: "proposal.md"}
    - {id: ST-2, name: Spec 增量设计, opsx: "/opsx:ff → specs", artifact: "delta-spec.md"}
    - {id: ST-3, name: Design 增量设计, opsx: "/opsx:ff → design", artifact: "design.md"}
    - {id: ST-4, name: 任务拆解, opsx: "/opsx:ff → tasks", artifact: "tasks.md"}
    - {id: ST-5, name: 开发实现, opsx: "/opsx:apply", artifact: "代码文件"}
    - {id: ST-6, name: 一致性验证, opsx: "/opsx:verify", artifact: "验证报告"}
